var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"그때 시선이 느껴졌어. 선체 아래의 바다에서 고래 몸집만 한 게 꿈틀대고 있었지.","JPN":"その時、視線を感じたんだ。船の下の海でクジラのような大きさの何かがうごめいたんだ。","ENG":"That's when I felt its gaze. Something under the ship, as big as a whale, was squirming.","TWN":"那個時候，我感覺到有什麼東西在盯著我，船身底下的水中有一條鯨魚大小的東西在蠕動。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"그건 생물의 눈동자였어. 엄청나게 거대한.","JPN":"それは生物の目だったんだ。とてつもなくデカい。","ENG":"It was an eye of a creature. A huge one at that.","TWN":"那是一種生物的眼睛，一雙非常大的眼睛。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"눈이라고? 정신없어서 헛것을 본 거 아냐?","JPN":"目だと？　慌てて変なものを見たんじゃないか？","ENG":"An eye? Are you sure you weren't hallucinating?","TWN":"眼睛？會不會是你眼花看錯？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"아냐, 똑똑히 봤어. 그런 소름 끼치는 걸 어떻게 잊겠냐고.","JPN":"いいや、確かに見た。あんな不気味なものは忘れられないよ。","ENG":"No, I saw it clear as day. How would I forget such a terrifying thing?","TWN":"不，我看得很清楚。那種毛骨悚然的感覺，我一輩子也忘不掉。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_CAREFUL","text":{"KOREA":"다른 녀석들 사이에서도 여러 목격담이 돌고 있더군. 집채만 한 꼬리가 선체를 노크하듯 두드렸다고도 하던데.","JPN":"他のやつらからも色々目撃したって話が出ている。家みたいな大きさの尻尾が船をノックするかのように叩いたとか。","ENG":"There are quite a few stories about its sightings. I heard a colossal tail hit the ship like it was knocking on a door.","TWN":"還有一些人也有目擊到，他們看到有一個房子大小的尾巴不停地敲擊著船身。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_CAREFUL","text":{"KOREA":"비명소리와 함께 연락이 두절된 팀도 있다는 모양이야.","JPN":"悲鳴と共に連絡が取れなくなったチームもあるらしい。","ENG":"Seems like some teams went missing after their last screams were heard through the radio.","TWN":"似乎還有些人，一邊慘叫一邊消失不見。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SCARED","text":{"KOREA":"역시 포기하는 게 좋겠어. 검은 범람을 뚫고 항해를 계속하는 건 무모한 짓이야.","JPN":"やっぱり諦めた方がいい。黒い氾濫の中を航海するのは無茶だ。","ENG":"We should give up. It's reckless to keep sailing through the Black Flood.","TWN":"還是放棄吧，繼續在黑色洪災中航行是非常不明智的行為。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_SCARED","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"쳇, 다른 녀석들이 겁주려고 퍼트리는 헛소문이겠지.","JPN":"ちっ、他のやつらが怖がすためにばら撒いた噂だろう。","ENG":"Tsk. It's probably just a rumor they're spreading to scare others.","TWN":"嘖，這是他們想嚇退其他人而散布的謠言吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"자기들끼리 토큰을 독차지하려고 괜한 수작부리는 거라고.","JPN":"自分たちでトークンを独り占めしようと手を打ったんだ。","ENG":"They're just playing tricks so they can hog all the tokens.","TWN":"是不是想獨吞賞金才耍這種小手段。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_CAREFUL","text":{"KOREA":"하지만 너도 느꼈잖아. 그 음산한 검은빛은 우리가 알던 바다가 아니었어.","JPN":"でもお前も感じただろう。あの気持ち悪い黒色は俺らが知っていた海じゃなかったんだ。","ENG":"But you felt it too, right? That creepy black hue isn't the ocean we know of.","TWN":"你不是也有感覺到嗎？那散發著陰森黑色光芒的大海，不是我們所熟悉的大海。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"這…"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_NULL_CAREFUL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"정말이야? 심해역에서 살아 돌아온 생존자라고?","JPN":"本当か？　深海域から生きて帰ってきた生存者だと？","ENG":"Is it true? They survived the deep sea area?","TWN":"你說真的？有人活著從深海域回來？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"살아 돌아온 것만이 아니야. 보물들을 잔뜩 싣고 왔어.","JPN":"ただ生きて帰ってきたんじゃない。宝物もたくさん持ってきたんだ。","ENG":"Not just survived. He brought a bunch of treasures with him.","TWN":"他不只活著回來，還帶回來不少的寶藏。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL2","text":{"KOREA":"자기가 보물사냥꾼이라고 하던데?","JPN":"自分をトレジャーハンターと名乗っていたぜ？","ENG":"Calls himself a treasure hunter.","TWN":"他自稱是寶藏獵人？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_DOUBT","text":{"KOREA":"보물사냥꾼…?","JPN":"トレジャーハンター……？","ENG":"Treasure hunter...?","TWN":"寶藏獵人…？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HUNTER_FRONTBAY_NULL_DOUBT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"당신, 그게 정말인가?","JPN":"アンタ、それは本当か？","ENG":"Hey, is it true?","TWN":"我問你，都是真的嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"그 값진 유물들을 전부 심해역에서 건졌다고?","JPN":"その高そうな宝を全部深海域から手に入れたって？","ENG":"You got all those valuables from the deep sea area?","TWN":"這些值錢的東西都是從深海域裡打撈上來的？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래. 전부 검은 범람과 함께 심해의 밑바닥에서 떠오른 것들이지.","JPN":"そう。全部黒い氾濫と共に深海の底から浮上したものだ。","ENG":"Aye. They all emerged from the depths of the ocean alongside the Black Flood.","TWN":"沒錯，這些東西都是隨著黑色洪災從海底浮上來的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리의 함선을 찾다가 배가 고장이 나버려서, 아쉬운 대로 챙겨온 것들이야.","JPN":"エイバリーの艦船を探していたら船が壊れてしまって、できるだけ持ってきたものだ。","ENG":"We were looking for Avery's ship, but our ship broke down. It's not a lot, but these are what we brought back.","TWN":"在尋找艾維利的艦船時我們的船壞掉，所以很可惜只能帶回這點東西。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"아쉽다고 하기엔… 전부 하나 같이 관리국에서 비싸게 쳐주는 유물들이잖아?","JPN":"残念と言うには……どれもこれも管理局が高く買い上げる宝じゃないか？","ENG":"Not a lot...? They're all valuable items that the Administration pays a high price for.","TWN":"真可惜…這些都是能向管理局高價出售的寶物呢。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SURPRISE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"뜻하지 않게 횡재했구만, 형씨. 다 팔아치우면 뭘 할 계획이지?","JPN":"儲かったな、兄ちゃん。全部売ったら何するつもりだ？","ENG":"You've come into a windfall, it seems. What will you do after selling all those?","TWN":"是筆意外之財呢，老兄。那你把這些東西全部賣掉後，接下來有什麼打算？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SURPRISE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"물론. 이 유물들을 처분하는 대로 다시 심해역으로 돌아가야지.","JPN":"この宝を処分する次第、また深海域に戻るに決まっている。","ENG":"Of course, I'll go back to the deep sea area after disposing of these treasures.","TWN":"等我們處理完這批寶物，當然是要回到深海域。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SURPRISE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"뭣?!","JPN":"なに！？","ENG":"What?!","TWN":"什麼？!"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_HATE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"미쳤군. 당신도 심해역에 뭐가 있는지 알 거 아냐! 그렇게 쉽게 또다시 목숨을 건다고?","JPN":"バカだな。あんたも深海域に何があるのかわかるだろう！　そんなに簡単に命をかけるのか？","ENG":"You're mad. You know what's in the deep sea area! And you'd still risk your life again?","TWN":"你瘋啦，你知道深海域裡有什麼嗎？你又想輕易地拿自己的性命冒險？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_HATE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫, 사람의 욕심에 끝이 어딨겠나.","JPN":"ハハハ、人は欲深いからな。","ENG":"Gah hah hah, there is no end to human greed, my friend.","TWN":"哈哈哈，人類的貪婪永無止境。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_HATE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"물론 나 혼자선 위험하다는 건 알고 있지.","JPN":"むろん、私一人では危ないということは良く知っている。","ENG":"Certainly, it would be dangerous if I were to go alone.","TWN":"當然，我知道我一個人很危險。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_HATE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 자네들이 함께 협력해준다면, 심해역으로 향하는 항로를 훨씬 안전하게 개척할 수 있을 거야.","JPN":"だが、君たちが協力してくれるなら、深海域へ向かう航路をより安全に開拓できるはずだ。","ENG":"However, with your help, we should be able to pave the way to the deep sea area much more safely.","TWN":"如果你們能助我一臂之力的話，我們就能開闢出一條更安全的深海域航道。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_HATE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"흥, 우릴 크라켄의 미끼로 쓰겠다고? 그렇게 말하면 우리가 순순히 따라갈 줄 알아?","JPN":"ふん、俺らをクラーケンの囮にするつもりだな？　そんなこと言ったってみすみすとついていくと思ったのか？","ENG":"Hmph. You want to use us as Kraken bait? You think we're going to just tag along?","TWN":"你想把我們當做克拉肯的誘餌？你覺得我們會同意嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_HATE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"그래! 그렇게 죽고 싶으면 잘난 당신 혼자 가라고!","JPN":"そうだ！　そんなに死にたければ、お前一人で行け！","ENG":"Yeah! If you have a death wish, go there alone!","TWN":"如果你那麼想死，那就自己去死吧！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SERIOUS"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐, 어디까지나 선택은 자네들의 몫이야.","JPN":"まぁ、選択はあくまでも君たちの分だ。","ENG":"The choice is yours.","TWN":"反正選擇權在你們手裡。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SERIOUS"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 바다에 떠다니는 보물은 검은 범람이 끝나면 다시 심해로 가라앉고 말겠지.","JPN":"でも海に漂う宝は黒い氾濫が終われば再び深い深海に沈んでしまうだろう。","ENG":"However, all the treasure floating in the sea will drown back down after the Black Flood.","TWN":"只是當黑色洪災結束後，漂浮在海面上的寶藏就又會重新沉入海底。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SERIOUS"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SURPRISE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_SURPRISE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HUNTER_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…아, 그러고보니 잊을 뻔했군.","JPN":"……あ、そういえば忘れるところだった。","ENG":"...Ah, I almost forgot.","TWN":"…喔，這麼說來，我差點忘了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이거 받아, 아가씨. 배 부품을 빌려준 답례라 생각하라고.","JPN":"受け取れ、お嬢さん。船の部品を借りてくれたお礼だ。","ENG":"Take this, lass. Think of it as payment for borrowing your ship's parts.","TWN":"拿著，小丫頭。就當是你把船的零件借給我的謝禮吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"응? 이건 총이잖아?","JPN":"ん？　これは銃？","ENG":"Hmm? This is a gun.","TWN":"嗯？這是把槍？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"우와아! 그건 뭐죠?","JPN":"うわあ！　これは何ですか？","ENG":"Whoaa! What's that?","TWN":"哇！那是什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"심해에서 건져올린 대박 희귀한 아티팩트?!","JPN":"深海から引き上げた凄く珍しいアーチファクト！？","ENG":"Is it a super rare Artifact you got from the deep sea area?!","TWN":"從深海域打撈上來的超稀有人造神器？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐만 주고 치사해요!","JPN":"ソーニャばかり、ずるいですわ！","ENG":"Unfair! Why is Sonya the only one getting something?!","TWN":"真小氣，竟然只給索妮雅一個人！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 예전에 쓰던 물건이다.","JPN":"昔、私が使った物だ。","ENG":"It's something I used in the past.","TWN":"這是我曾經用過的東西。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"회칼도 좋지만, 긴급한 상황에선 이만한 도구도 없거든.","JPN":"刺身包丁もいいが、緊急な時にはこれが一番だ。","ENG":"A knife is fine, but this can be very helpful in urgent situations.","TWN":"短刀雖然好，但在緊要關頭，沒有比槍更實用的東西。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"에이, 아저씨 손때가 탄 무기? 전 사양할게요.","JPN":"ええ、おじさんが使った武器？　私は遠慮します。","ENG":"Whaaat? Your dirty secondhand weapon? I'll pass.","TWN":"蛤？是大叔用過的武器喔？那我不要了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫, 새것이 아니라 미안하군.","JPN":"ハハハ、新品でなくて悪いな。","ENG":"Gah hah hah, I'm sorry it's not shiny and new.","TWN":"哈哈哈，抱歉，不是新的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"나, 총 같은 건 쏠 줄 모르는데.","JPN":"あたし、銃なんか撃てないんだけど。","ENG":"I don't know how to shoot a gun.","TWN":"我不會用槍。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"상관없어. 제법 효과가 좋은 아티팩트라 위험할 때 아무데나 대고 쏘면 되거든.","JPN":"構わない。かなり効果があるアーティファクトだから、危ない時に適当に撃てばいいんだ。","ENG":"It doesn't matter. It's an effective Artifact, so when you're in danger, just aim at anything and shoot.","TWN":"沒關係，它是效果很不錯的人造神器，當你遇到危險時可以把它射向任何東西。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"뭐… 답례라니까 일단은 잘 쓸게.","JPN":"まぁ……お礼って言うから、とりあえず貰っておくよ。","ENG":"Well... Since it's payment, I'll take it.","TWN":"嗯…既然是謝禮，我就先收下。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그런데 앞으로 어쩔 셈이야?","JPN":"ところで、これからどうするの？","ENG":"What will you do now?","TWN":"你之後打算做什麼？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"바뀐 건 없어. 날이 밝는 대로 정비를 하고 다시 출항해야지.","JPN":"変わるものはないさ。夜が明け次第、整備を整えて再び出航する。","ENG":"Nothing's changed. I'll go back to the embrace of the ocean once the sun rises.","TWN":"一切照舊，天一亮我們就會回到海上。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"괜찮아? 아무도 당신을 따라갈 생각이 없어 보이던데.","JPN":"いいの？　誰もあなたについていこうとは思わないようだが。","ENG":"Will you be all right? No one seemed to be convinced to follow you.","TWN":"沒關係嗎？似乎沒有人願意跟你回去。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그런가?","JPN":"そうか？","ENG":"You think so?","TWN":"是嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그야 두고 보면 알겠지.","JPN":"それは見ればわかるさ。","ENG":"I guess time will tell.","TWN":"我們拭目以待。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"만족을 모르는 사람이네요. 저렇게 벌어 놓고도 또 다시 사지로 들어가려 하다니.","JPN":"満足を知らない人ですね。あんなに稼いでおいてまた死にに行くとは。","ENG":"He really doesn't know when to stop. I can't believe he's risking his life again right after making that much money.","TWN":"真是個不知滿足的人，賺那麼多錢還不夠，還要再去冒險。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"뭐- 그러니까 해적인 거겠죠! 제법 낭만이네요!","JPN":"まぁーだから海賊なんでしょうね！　結構ロマンチックじゃないですか！","ENG":"Well, I guess that's the pirate dream! It's pretty cool!","TWN":"嗯，不過這才是海盜嘛！真是浪漫！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하아암-","JPN":"ふああんー","ENG":"*Yawn...*","TWN":"哈啊阿～"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"아, 선장님이 깨어났다!","JPN":"あ、船長が起きた！","ENG":"Oh, Captain's awake!","TWN":"喔？船長醒啦！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"너희들…? 어떻게 된 거야? 언제 부두로 돌아온 거고?","JPN":"お前ら……？　どういうことだ？　いつ港に戻ってきた？","ENG":"You... What happened? When did we get back to the docks?","TWN":"你們…？這是怎麼回事？我們什麼時候回到碼頭的？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"단도직입적으로 말하면…","JPN":"簡単に言うと……","ENG":"I'll cut to the chase...","TWN":"簡單來說…"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"우리, 새 배가 필요할 것 같아.","JPN":"あたしたち、新しい船が必要になったようだ。","ENG":"We're going to need a new boat.","TWN":"我們需要再買一艘新船。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"…엉?","JPN":"……ん？","ENG":"...Huh?","TWN":"…蛤？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"제, 제가 부숴먹었냐는 눈빛으로 쳐다보셔도 어쩔 수 없어요! 이번엔 제 탓이 아니라구요!","JPN":"わ、私が壊したのかっていう目で見ても仕方ないのです！　今回は私のせいじゃないんですから！","ENG":"S-stop looking at me like I broke the ship! It wasn't me this time!","TWN":"別這麼看著我，弄壞它的人又不是我！這也是沒辦法的事！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흐음- 내가 잠든 사이 그런 일이 있었단 말이지.","JPN":"ふーん、あたしが寝ている間にそんなことがあったのか……","ENG":"Hmm... So that's what happened while I was asleep.","TWN":"嗯…是在我睡著的時候發生的事吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어라? 왜 배를 포기했냐고 화내실 줄 알았는데, 의외네요.","JPN":"あら？　何で船を諦めたのかって怒るのかと思ったのに、意外ですね。","ENG":"Huh? I thought you'd be angry that I gave up the ship.","TWN":"喔？我還以為你會因為我棄船而發火呢，真是意外。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐 어때. 곧 있으면 떼돈을 벌게 될 텐데 그깟 보트 하나쯤이야.","JPN":"まあいいじゃん。もうすぐ大儲けできるのにあんなボート一つくらい。","ENG":"Eh, it's fine. We're going to make a fortune soon, and it was a measly boat.","TWN":"管他呢，反正很快就會大賺一筆，不過就是一艘船而已。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어쩌죠, 소냐? 선장님이 또 대책 없이 희망회로를 태우고 있는 거 같아요.","JPN":"ソーニャ、どうしましょう？　船長がまた対策もないのに夢を見ているようです。","ENG":"What do we do, Sonya? I think Captain's being unrealistically optimistic again.","TWN":"怎麼辦，索妮雅？船長又開始幻想不切實際的計畫。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선장, 정말 다시 바다로 나갈 셈이야?","JPN":"船長、本当にまた海に出るつもりか？","ENG":"Captain, are you really going to head out to the ocean again?","TWN":"船長，你確定要出海嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"심해역에 보물들이 떠다니고 있다며? 그럼 당연히 가야지.","JPN":"深海域に宝が浮いているんだろ？　なら当然行くさ。","ENG":"You said there were treasures floating in the deep sea area. Of course we do.","TWN":"不是說深海域裡有寶藏？那就要去看看吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하지만 이번처럼 살아 돌아올 거라곤 장담 못해.","JPN":"しかし今回のように生きて帰れるという保障はないよ。","ENG":"There's no guarantee that we'll make it out alive like this time.","TWN":"不過我不保證這次也能平安回來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"빠질 사람은 지금이라도 빠져도 좋아.","JPN":"抜けたい人は今からでも抜けていい。","ENG":"So, I won't stop you if you're not willing to risk that.","TWN":"有人想離開的話，現在就可以離開。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"전 갈래요!","JPN":"私、行きます！","ENG":"I wanna go!","TWN":"我要一起去！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"탈리, 이건 진지한 문제야. 한 번 결정하면, 무르지 못한다고.","JPN":"タリー、これは真剣な問題だ。一度決めたら、後戻りはできない。","ENG":"Tallie, this is a serious matter. Once you make a decision, there's no going back.","TWN":"塔莉，這是一件嚴肅的事情，一旦做出決定，就不能反悔。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님이 저 처음 입단할 때 말했잖아요!","JPN":"私が入団した時、船長が言ったでしょう！","ENG":"You told me when I first joined the crew!","TWN":"船長，我剛加入時你就告訴我了！"},"stage":{"bg":"CLUB1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장은 배를 버릴지언정, 선원은 절대로 버리지 않는다고요!","JPN":"船長は船を捨てても、船員は絶対に捨てないって！","ENG":"A captain might abandon her ship, but never her crew!","TWN":"船長可以棄船，但絕不能拋棄船員！"},"stage":{"bg":"CLUB1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그렇다면 저도 선장을 버리지 않겠어요!","JPN":"だったら私も船長を捨てません！","ENG":"Then I won't abandon you either!","TWN":"那我也不會拋棄船長！"},"stage":{"bg":"CLUB1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저, 선장님의 그 말씀! 단 한 순간도 잊은 적 없으니까요!","JPN":"私、船長のその言葉！　一度も忘れたことありませんわ！","ENG":"Because I never ever forgot what you said!","TWN":"船長，你說過的話！我一刻也沒有忘記！"},"stage":{"bg":"CLUB1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"탈리…","JPN":"タリー……","ENG":"Tallie...","TWN":"塔莉…"},"stage":{"bg":"CLUB1","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"내가 그런 대사를 친 적이 있었나?","JPN":"あたしって、そんなこと言ってたっけ？","ENG":"I don't think it was me who said that.","TWN":"我有說過那句話嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"엣, 아닌가? 얼마 전에 봤던 해적 영화랑 헷갈렸나 봐요.","JPN":"えっ、言ってません？　この前みた海賊映画と間違えたようです。","ENG":"Uh, it isn't? Maybe it's from a pirate movie I saw recently.","TWN":"欸，沒有嗎？我不久前看了一部海盜電影，可能是我記錯了。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어쨌든 낭만적이었으면 된 거 아닐까요?","JPN":"とにかくロマンチックだったからいいんでしょう？","ENG":"Well, it doesn't matter as long as it sounds cool!","TWN":"不管怎樣，重點是浪漫就好。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"소냐? 넌?","JPN":"ソーニャ？　お前は？","ENG":"What about you, Sonya?","TWN":"索妮雅？你呢？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"나야 뭐, 선장이 까라면 까야지.","JPN":"あたしも、まぁー船長がそういうなら従うよ。","ENG":"Me? I'll go if the captain wants to go.","TWN":"我嘛，船長說去哪，我就去哪。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"낭만이 없네요! 소냐! 무슨 멘트가 그렇게 시시해요!","JPN":"ロマンがないですね！　ソーニャ！　セリフがつまらないです！","ENG":"That's lame, Sonya! Can't you think of a cooler line?!","TWN":"真不浪漫，索妮雅！這種回答真是無趣！"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"솔직히 말하면, 선장 혼자 보물을 잔뜩 챙겨서 갑부 되는 상상을 했더니 배가 아프더라.","JPN":"正直に言うと、船長一人で宝をたくさん手に入れて金持ちになると思ったらお腹が痛い。","ENG":"Honestly, I couldn't stomach the thought of Captain hogging all the treasure and becoming rich.","TWN":"說實話的話，一想到船長自己獨吞一大堆寶藏變身富翁，我就難受得要死。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그건 저도 동감이에요. 곧 죽어도 선장 혼자 잘 되는 꼴은 못 보죠.","JPN":"それは私も同じです。船長一人良くなるのは絶対許しません。","ENG":"I agree. I'd rather die than see her become rich alone.","TWN":"我也是這麼想的。就算死，我也不想看到船長一個人快活。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫, 역시 내 선원들답구만.","JPN":"キャハハッ、さすがあたしの船員だな。","ENG":"Kya hah hah, there's my crew!","TWN":"哈哈哈，不愧是我的船員。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그런데, 배는 어쩔 셈이야?","JPN":"ところで、船はどうするつもりだ？","ENG":"But what about our ship?","TWN":"不過，船要怎麼辦？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"우리 배가 없는 건 잭 아저씨 책임도 있으니, 빌려 탈 수 있지 않을까요?","JPN":"私の船がないのはジャックおじさんの責任もあるから、乗せてもらえるんじゃないんですか？","ENG":"Since it's partially Jack's fault that we don't have a ship, maybe we can ride along?","TWN":"我們現在沒有船傑克大叔也要負責，也許我們可以借他的船出海？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그건 안돼. 한 배를 타는 순간 보수도 그 녀석들과 나눠 갖겠다는 뜻이니까.","JPN":"それはだめだ。同じ船に乗る瞬間報酬もそいつらと分けることになるんだ。","ENG":"No. If we sail with them, that'll mean we'd have to share the loot too.","TWN":"不行，只要上了船，就必須和他們分享你的收穫。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그때가 되면 분명 땅을 치고 후회할 걸?","JPN":"その時になるときっと涙を流しながら後悔するよ？","ENG":"And when the time comes, we'll surely regret it.","TWN":"那你一定會後悔的。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그럼, 배는 또다시 빌리는 수밖에 없겠네.","JPN":"じゃあ、船はまた借りるしかないか。","ENG":"I guess we have no choice but to rent a ship again.","TWN":"那我們又要租船了。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"야, 터커. 다 듣고 있지?","JPN":"おい、ターカー。聞いているだろ？","ENG":"Hey, Tucker. You were listening, right?","TWN":"喂，塔克。你都聽到了吧？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"으, 응? 나 말이야?","JPN":"う、うん？　俺か？","ENG":"H-huh? Me?","TWN":"呃，嗯？我？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"네 배 좀 빌린다. 운전은 당연히 네가 맡고.","JPN":"お前の船、借りるよ。運転は任せる。","ENG":"We're gonna take your ship. And you'll be operating it.","TWN":"嗯，把你的船借給我。當然，你負責開船。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"잠깐만…! 왜 갑자기 그렇게 결정이 되는 건데? 난 가기 싫어!","JPN":"ちょっと待って……！　何でいきなりそんなことになるんだ？　俺は行きたくない！","ENG":"Wait...! I didn't agree to that! I don't wanna go!","TWN":"等等…！為什麼突然找我？我不想去！"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그럼 보물이 코앞에 있는데 겁쟁이처럼 부두에 틀어박혀 있기나 할 거냐?","JPN":"じゃあ宝物が目の前にあるのに臆病者のように港に閉じこもっているつもりか？","ENG":"So, there's an absurd amount of treasure in front of us, and you're going to be stuck here like a coward?","TWN":"寶藏就在眼前，你卻要像個懦夫一樣待在碼頭上？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"우리가 너 같은 허접 해적을 끼워주는 것만으로도 감사히 여기라고.","JPN":"あたしたちがお前みたいなヘタクソ海賊を仲間に入れてくれるだけでありがたく思えよ。","ENG":"You should be grateful that we're willing to include a scurvy dog like you.","TWN":"你應該慶幸我們還能容忍你這個懦弱的海盜嘍囉。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"떼돈을 벌 기회를 두고도 모른 척하는 겁쟁이 터커 씨가 저희와 같은 해적이라니. 해적의 수치네요.","JPN":"大儲けできるチャンスを目の前にしても知らないふりをする臆病なターカーさんが私たちと同じ海賊だなんて、海賊の恥ですわね。","ENG":"Wow. The cowardly Tucker who is turning away from treasure is a pirate just like us? You're a disgrace to all other pirates!","TWN":"懦夫塔克，放著發財的機會不理，在這裝傻的你，還有一點海盜的樣子嗎？簡直就是海盜的恥辱。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"누가 겁쟁이란 거야! 너희가 무모한 거지!","JPN":"誰が臆病者だ！　お前らが無茶すぎるんだ！","ENG":"Who are you calling a coward! You're just reckless!","TWN":"你說誰是懦夫！是你們太魯莽吧！"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"격벽이 열린 지 겨우 하루만에 바다로 나간 녀석들 전부 낙오하거나 실종됐어.","JPN":"隔壁が開いてから一日しか立っていないのに、海に出たやつらは全員諦めたか、いなくなったんだ。","ENG":"It's been only a day since the bulwark opened, and most of the people who went out to sea fell behind or went missing.","TWN":"隔離牆才打開一天，那些出海的船隻不是遇難就是失蹤。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"지금 바다로 나가는 게 미친 짓이란 건 모두가 아는 사실이라고!","JPN":"今、海に出るのがバカみたいなことだっていうのは、みんな知っている！","ENG":"Everyone knows you have to be insane to go out to sea right now!","TWN":"現在這種情況，只要沒瘋，就不會選擇出海！"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"뭐, 우리도 간신히 살아서 돌아온 입장이니 그 점은 반박 못하겠네.","JPN":"まぁ、あたしたちも辛うじて生きて帰ってきたからその点、何とも言えないね。","ENG":"Well, I can't argue with that, since we just barely made it out alive.","TWN":"嗯，這點無法反駁，我們也是好不容易才活著回來的。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"나뿐만인 줄 알아? 프론트베이의 그 어떤 해적이나 헌터도 다 같은 생각일걸?","JPN":"俺だけじゃない！　フロントベイの海賊もハンターもみんな同じ考えだぞ？","ENG":"It's not just me. Any pirate or hunter in Front Bay would agree.","TWN":"你以為只有我這麼想嗎？前灣的其他海盜或者獵人大概也是一樣的想法。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"좋아. 그럼 이건 어때?","JPN":"よし。それじゃ、これはどうだ？","ENG":"Fine. Then what about this?","TWN":"好吧，這樣如何？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"내일 새벽이 밝았을 때 출항을 준비하는 배가 열 척이 넘으면, 그땐 너도 네가 겁쟁이가 아니라는 걸 증명하는 거야.","JPN":"明日の夜明け、出航を準備する船が十隻以上あれば、その時はお前も自分が臆病者ではないことを証明するんだ。","ENG":"Tomorrow, at dawn, if there are over 10 ships that are getting ready to set sail, you have to prove that you're not a coward.","TWN":"明天太陽升起時，如果有十艘以上的船準備出海，那你就證明自己不是懦夫。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"내, 내가 왜 그런 내기를 받아들여야 하는데?!","JPN":"な、何で俺がそんな賭けに乗らなければならないんだ！？","ENG":"W-why on earth would I agree to that?!","TWN":"我為什麼要跟你賭？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"네 입으로 프론트베이 바다에는 헌터들 도움따윈 필요없다며?","JPN":"お前、自分の口でフロントベイの海にはハンターの手助けなんて必要ないって言ったじゃん？","ENG":"You said it yourself that Front Bay's ocean doesn't need the help of hunters.","TWN":"是你說的，前灣海域不需要獵人的幫忙。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"설마 그 정도 배짱도 없으면서 그런 소릴 했던 걸까나?","JPN":"まさかそれくらいの度胸もないくせに、そんなことを言ったのかな？","ENG":"Did you say that without any courage to back it up?","TWN":"連打賭的膽量都沒有，還好意思說出這種話？"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L6_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"쳇…","JPN":"ちっ……","ENG":"Tch...","TWN":"嘖…"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"좋아. 까짓 거 내기해 보자고.","JPN":"いいよ。やろうじゃないか。","ENG":"Fine. I'll do it.","TWN":"好吧，我跟你賭。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TUCKER_FRONTBAY_NULL_NULL","text":{"KOREA":"항구 놈들이 돈에 눈이 먼 멍청이도 아니고, 너희처럼 바다로 나갈 사람은 아무도 없을 테니까.","JPN":"港のやつらが金に目がないバカでもあるまいし、お前らみたいに海に出るやつなんか誰もいないはずだからな。","ENG":"The people of Front Bay aren't money-hungry idiots. No one's going to be setting sail tomorrow anyway.","TWN":"港口的傢伙可不是一群見錢眼開的傻子，沒有人會像你們一樣選擇出海的。"},"stage":{"bg":"CLUB1","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TUCKER_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};